const unique_names: Set<string> = new Set();

let attribute;
while ((attribute = read_attribute(parser, unique_names))) {
	element.attributes.push(attribute);
	parser.allow_whitespace();
}

function read_attribute(parser: Parser, unique_names: Set<string>) {
	const start = parser.index;

	function check_unique(name: string) {
		if (unique_names.has(name)) {
			parser.error({
				code: 'duplicate-attribute',
				message: 'Attributes need to be unique'
			}, start);
		}
		unique_names.add(name);
	}

// eslint-disable-next-line no-useless-escape
const name = parser.read_until(/[\s=\/>"']/);
if (!name) return null;

let end = parser.index;

parser.allow_whitespace();

const colon_index = name.indexOf(':');
const type = colon_index !== -1 && get_directive_type(name.slice(0, colon_index));

let value: any[] | true = true;
if (parser.eat('=')) {
	parser.allow_whitespace();
	value = read_attribute_value(parser);
	end = parser.index;
} else if (parser.match_regex(/["']/)) {
	parser.error({
		code: 'unexpected-token',
		message: 'Expected ='
	}, parser.index);
}

if (type) {
	const [directive_name, ...modifiers] = name.slice(colon_index + 1).split('|');

	if (type === 'Binding' && directive_name !== 'this') {
		check_unique(directive_name);
	} else if (type !== 'EventHandler') {
		check_unique(name);
	}

	if (type === 'Ref') {
		parser.error({
			code: 'invalid-ref-directive',
			message: `The ref directive is no longer supported — use \`bind:this={${directive_name}}\` instead`
		}, start);
	}

	if (value[0]) {
		if ((value as any[]).length > 1 || value[0].type === 'Text') {
			parser.error({
				code: 'invalid-directive-value',
				message: 'Directive value must be a JavaScript expression enclosed in curly braces'
			}, value[0].start);
		}
	}

	const directive: Directive = {
		start,
		end,
		type,
		name: directive_name,
		modifiers,
		expression: (value[0] && value[0].expression) || null
	};

	if (type === 'Transition') {
		const direction = name.slice(0, colon_index);
		directive.intro = direction === 'in' || direction === 'transition';
		directive.outro = direction === 'out' || direction === 'transition';
	}

	if (!directive.expression && (type === 'Binding' || type === 'Class')) {
		directive.expression = {
			start: directive.start + colon_index + 1,
			end: directive.end,
			type: 'Identifier',
			name: directive.name
		} as any;
	}

	return directive;
}

check_unique(name);

return {
	start,
	end,
	type: 'Attribute',
	name,
	value
};

if (type === 'Binding' && directive_name !== 'this') {
	check_unique(directive_name);
} else if (type !== 'EventHandler') {
	check_unique(name);
}

function get_directive_type(name: string): DirectiveType {
	if (name === 'use') return 'Action';
	if (name === 'animate') return 'Animation';
	if (name === 'bind') return 'Binding';
	if (name === 'class') return 'Class';
	if (name === 'on') return 'EventHandler';
	if (name === 'let') return 'Let';
	if (name === 'ref') return 'Ref';
	if (name === 'in' || name === 'out' || name === 'transition') return 'Transition';
}
